+describe('PreferencesService', () => {
+  let service: PreferencesService;
+
+  beforeEach(() => {
+    service = new PreferencesService();
+  });
+
+  describe('getPreferences', () => {
+    it('should return default preferences for unknown user', () => {
+      const prefs = service.getPreferences('user-1');
+      expect(prefs.userId).toBe('user-1');
+      expect(prefs.enabled).toBe(true);
+      expect(prefs.email.enabled).toBe(true);
+      expect(prefs.email.frequency).toBe('immediate');
+      expect(prefs.email.subscribedCategories).toEqual([
+        'order-confirmation',
+        'order-status-update',
+        'welcome',
+        'account-update',
+      ]);
+    });
+
+    it('should return a copy (not a reference) of preferences', () => {
+      service.updatePreferences('user-1', { enabled: true });
+      const prefs1 = service.getPreferences('user-1');
+      const prefs2 = service.getPreferences('user-1');
+      prefs1.email.subscribedCategories.push('order-confirmation');
+      expect(prefs2.email.subscribedCategories).not.toEqual(prefs1.email.subscribedCategories);
+    });
+  });
+
+  describe('updatePreferences', () => {
+    it('should update the master enabled flag', () => {
+      const prefs = service.updatePreferences('user-1', { enabled: false });
+      expect(prefs.enabled).toBe(false);
+      expect(prefs.email.enabled).toBe(true); // unchanged
+    });
+
+    it('should update email enabled independently', () => {
+      const prefs = service.updatePreferences('user-1', {
+        email: { enabled: false },
+      });
+      expect(prefs.enabled).toBe(true); // unchanged
+      expect(prefs.email.enabled).toBe(false);
+    });
+
+    it('should update email frequency', () => {
+      const prefs = service.updatePreferences('user-1', {
+        email: { frequency: 'daily' },
+      });
+      expect(prefs.email.frequency).toBe('daily');
+      expect(prefs.email.enabled).toBe(true); // unchanged
+    });
+
+    it('should update subscribed categories', () => {
+      const prefs = service.updatePreferences('user-1', {
+        email: { subscribedCategories: ['order-confirmation'] },
+      });
+      expect(prefs.email.subscribedCategories).toEqual(['order-confirmation']);
+    });
+
+    it('should persist updates across calls', () => {
+      service.updatePreferences('user-1', { email: { frequency: 'weekly' } });
+      const prefs = service.getPreferences('user-1');
+      expect(prefs.email.frequency).toBe('weekly');
+    });
+
+    it('should apply partial updates without losing other fields', () => {
+      service.updatePreferences('user-1', {
+        email: { frequency: 'daily' },
+      });
+      service.updatePreferences('user-1', {
+        email: { enabled: false },
+      });
+      const prefs = service.getPreferences('user-1');
+      expect(prefs.email.frequency).toBe('daily');
+      expect(prefs.email.enabled).toBe(false);
+    });
+  });
+
+  describe('shouldSendEmail', () => {
+    it('should return true for default preferences', () => {
+      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
+    });
+
+    it('should return false when master switch is off', () => {
+      service.updatePreferences('user-1', { enabled: false });
+      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
+    });
+
+    it('should return false when email is disabled', () => {
+      service.updatePreferences('user-1', { email: { enabled: false } });
+      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
+    });
+
+    it('should return false for unsubscribed category', () => {
+      service.updatePreferences('user-1', {
+        email: { subscribedCategories: ['welcome'] },
+      });
+      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
+      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
+    });
+  });
+
+  describe('resetPreferences', () => {
+    it('should restore defaults after reset', () => {
+      service.updatePreferences('user-1', { enabled: false });
+      const prefs = service.resetPreferences('user-1');
+      expect(prefs.enabled).toBe(true);
+      expect(prefs.email.enabled).toBe(true);
+      expect(prefs.email.frequency).toBe('immediate');
+    });
+  });
+
+  describe('deletePreferences', () => {
+    it('should return true when preferences existed', () => {
+      service.updatePreferences('user-1', { enabled: false });
+      expect(service.deletePreferences('user-1')).toBe(true);
+    });
+
+    it('should return false when no preferences existed', () => {
+      expect(service.deletePreferences('user-1')).toBe(false);
+    });
+
+    it('should return defaults after deletion', () => {
+      service.updatePreferences('user-1', { enabled: false });
+      service.deletePreferences('user-1');
+      expect(service.getPreferences('user-1').enabled).toBe(true);
+    });
+  });
+});
+
+describe('NotificationService with preferences', () => {
+  let eventBus: EventBus;
+  let notificationService: NotificationService;
+  let emailAdapter: EmailNotificationAdapter;
+  let preferencesService: PreferencesService;
+
+  beforeEach(() => {
+    eventBus = new EventBus();
+    notificationService = new NotificationService(eventBus);
+    emailAdapter = new EmailNotificationAdapter();
+    notificationService.registerAdapter(emailAdapter);
+    preferencesService = new PreferencesService();
+    notificationService.setPreferencesService(preferencesService);
+    resetNotificationIdCounter();
+  });
+
+  const orderCreatedEvent: OrderCreatedEvent = {
+    type: 'order:created',
+    order: {
+      id: 'order-1',
+      userId: 'user-1',
+      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
+      total: 10,
+      status: 'pending',
+      createdAt: new Date(),
+      updatedAt: new Date(),
+    },
+    user: {
+      id: 'user-1',
+      name: 'Alice',
+      email: 'alice@example.com',
+      role: 'member',
+      createdAt: new Date(),
+      updatedAt: new Date(),
+    },
+    timestamp: new Date(),
+  };
+
+  const statusChangedEvent: OrderStatusChangedEvent = {
+    type: 'order:status-changed',
+    order: {
+      id: 'order-1',
+      userId: 'user-1',
+      items: [],
+      total: 10,
+      status: 'confirmed',
+      createdAt: new Date(),
+      updatedAt: new Date(),
+    },
+    previousStatus: 'pending',
+    newStatus: 'confirmed',
+    timestamp: new Date(),
+  };
+
+  it('should send notification when preferences allow it', async () => {
+    await eventBus.emit(orderCreatedEvent);
+    expect(notificationService.getNotificationCount()).toBe(1);
+    expect(emailAdapter.getSentEmails()).toHaveLength(1);
+  });
+
+  it('should suppress notification when master switch is off', async () => {
+    preferencesService.updatePreferences('user-1', { enabled: false });
+    await eventBus.emit(orderCreatedEvent);
+    expect(notificationService.getNotificationCount()).toBe(0);
+    expect(emailAdapter.getSentEmails()).toHaveLength(0);
+  });
+
+  it('should suppress notification when email is disabled', async () => {
+    preferencesService.updatePreferences('user-1', { email: { enabled: false } });
+    await eventBus.emit(orderCreatedEvent);
+    expect(notificationService.getNotificationCount()).toBe(0);
+  });
+
+  it('should suppress notification for unsubscribed category', async () => {
+    preferencesService.updatePreferences('user-1', {
+      email: { subscribedCategories: ['welcome'] },
+    });
+    await eventBus.emit(orderCreatedEvent);
+    expect(notificationService.getNotificationCount()).toBe(0);
+  });
+
+  it('should send status update when user is subscribed to that category', async () => {
+    await eventBus.emit(statusChangedEvent);
+    expect(notificationService.getNotificationCount()).toBe(1);
+  });
+
+  it('should suppress status update when unsubscribed from that category', async () => {
+    preferencesService.updatePreferences('user-1', {
+      email: { subscribedCategories: ['order-confirmation'] },
+    });
+    await eventBus.emit(statusChangedEvent);
+    expect(notificationService.getNotificationCount()).toBe(0);
+  });
+
+  it('should allow per-user independent preferences', async () => {
+    // Disable user-1's order confirmations
+    preferencesService.updatePreferences('user-1', {
+      email: { subscribedCategories: ['order-status-update'] },
+    });
+
+    await eventBus.emit(orderCreatedEvent);
+    expect(notificationService.getNotificationCount()).toBe(0);
+
+    // Status change should still work for user-1
+    await eventBus.emit(statusChangedEvent);
+    expect(notificationService.getNotificationCount()).toBe(1);
+  });
+});

